import mysql.connector
from mysql.connector import Error
import os

# Get file path from user input
file_path = input("Enter the file path to import data: ")

try:
    # Enable local_infile in MySQL config and Python connector
    cnx = mysql.connector.connect(
        user='username',
        password='password',
        host='localhost',
        database='database'
    )
    cursor = cnx.cursor()
    
    query = "SET GLOBAL local_infile = 1;"
    cursor.execute(query)
    
    # Create a dictionary to store the LOAD DATA INFILE statements
    load_data_statements = {
        'table1': "LOAD DATA INFILE '{}' INTO TABLE table1 FIELDS TERMINATED BY ',' ENCLOSED BY '\"' LINES TERMINATED BY '\n';",
        'table2': "LOAD DATA INFILE '{}' INTO TABLE table2 FIELDS TERMINATED BY ',' ENCLOSED BY '\"' LINES TERMINATED BY '\n';"
    }
    
    # Get the table name from user input
    table_name = input("Enter the table name to import data: ")
    
    if table_name in load_data_statements:
        query = load_data_statements[table_name].format(file_path)
        cursor.execute(query)
        
        cnx.commit()
        print("Data imported successfully.")
    else:
        print("Invalid table name. Please enter a valid table name.")
except Error as e:
    print(f"Error: {e}")
finally:
    if (cnx.is_connected()):
        cursor.close()
        cnx.close()

# Prevent datastore security
os.system('mysql -u username -p password database < script.sql')